// Controllers/ProductController.cs
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using YourNamespace.Models;
using Microsoft.EntityFrameworkCore;

public class ProductController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductController(ApplicationDbContext context)
    {
        _context = context;
    }

    // Display reviews for a product with given id
    public async Task<IActionResult> ShowReviews(int id)
    {
        var reviews = await _context.Reviews
            .Where(r => r.ProductId == id)
            .ToListAsync();

        return View(reviews);
    }
}

// Views/Reviews/Index.cshtml (Razor view)
@model List<YourNamespace.Models.Review>

@{
    var allowedHtmlTags = "<b><i>"; // only allow bold and italic tags
}

<h2>Product Reviews</h2>

@foreach (var review in Model)
{
    <div>
        @Html.Raw(SanitizeHtml(review.Content, allowedHtmlTags))
    </div>
}

public static MvcHtmlString SanitizeHtml(string rawHtml, string allowedHtmlTags)
{
    var doc = new HtmlDocument();
    doc.LoadHtml(rawHtml);

    var nodes = doc.DocumentNode
        .Descendants()
        .Where(n => n.HasAttributes && !allowedHtmlTags.Contains(n.Name))
        .ToList();

    foreach (var node in nodes)
    {
        node.Remove();
    }

    return new MvcHtmlString(doc.DocumentNode.OuterHtml);
}